const media = $json;

return [
  {
    json: {
      featured_media_id: media.id,
      image_url: media.source_url || media.guid?.rendered || media.guid?.raw || ""
    }
  }
];

const results = $input.all();
const article = $('Format').item.json;

const normalize = (s) =>
  (s || "")
    .toString()
    .trim()
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");

const slugify = (s) =>
  normalize(s)
    .replace(/[^a-z0-9\s-]/g, "")
    .replace(/\s+/g, "-")
    .replace(/-+/g, "-")
    .replace(/^-|-$/g, "");

const finalCategory = article.category || "Sin categoría";
const targetName = normalize(finalCategory);
const targetSlug = slugify(finalCategory);

const matchedCategory = results.find(item => {
  const j = item.json || {};

  return j.id && (
    normalize(j.name) === targetName ||
    normalize(j.slug) === targetSlug
  );
});

const baseData = {
  ...article,
  category: finalCategory,
};

if (matchedCategory) {
  return [
    {
      json: {
        ...baseData,
        categoryId: Number(matchedCategory.json.id),
        categoryName: matchedCategory.json.name || finalCategory,
        exists: true,
        categoryReady: true
      },
    },
  ];
}

return [
  {
    json: {
      ...baseData,
      categoryId: null,
      categoryName: finalCategory,
      exists: false,
      categoryReady: false
    },
  },
];

return [
  {
    json: {
      ...$json,
      categoryId: Number($json.categoryId),
      categoryName: $json.categoryName || $json.category,
      categoryReady: true
    }
  }
];

const rawOriginal =
  $json.text ||
  $json.output ||
  $json.response ||
  $json.message ||
  $json.content ||
  "";

let raw = String(rawOriginal)
  .replace(/```json/gi, "")
  .replace(/```/g, "")
  .trim();

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (e) {

  // Buscar el primer objeto JSON válido dentro del texto
  const jsonMatch = raw.match(/\{[\s\S]*\}/);

  if (!jsonMatch) {
    throw new Error(
      "No se encontró JSON válido en la respuesta del LLM: " +
      raw.slice(0, 700)
    );
  }

  try {
    parsed = JSON.parse(jsonMatch[0]);
  } catch (err) {
    throw new Error(
      "El JSON del LLM no se pudo parsear: " +
      jsonMatch[0].slice(0, 700)
    );
  }
}

const clean = (v) =>
  v == null ? "" : String(v).trim();

const category = clean(
  parsed.category ||
  $json.category ||
  $json.custom_category
);

const keyword = clean(
  parsed.keyword ||
  $json.keyword
);

const title_wordpress = clean(parsed.title_wordpress);
const content_wordpress = clean(parsed.content_wordpress);

if (!title_wordpress) {
  throw new Error(
    "Falta title_wordpress en el JSON del LLM."
  );
}

if (!content_wordpress) {
  throw new Error(
    "Falta content_wordpress en el JSON del LLM."
  );
}

return [
  {
    json: {
      ...$json,

      // Compatibilidad con el flujo antiguo WP
      title: title_wordpress,
      content: content_wordpress,
      tags: clean(parsed.tags_wordpress),

      category,
      keyword,

      image_prompt: clean(parsed.image_prompt),

      // =========================
      // WORDPRESS
      // =========================
      title_wordpress,
      content_wordpress,
      tags_wordpress: clean(parsed.tags_wordpress),

      // =========================
      // LINKEDIN
      // =========================
      title_linkedin: clean(parsed.title_linkedin),
      content_linkedin: clean(parsed.content_linkedin),
      tags_linkedin: clean(parsed.tags_linkedin),

      // =========================
      // X / TWITTER
      // =========================
      title_x: clean(parsed.title_x),
      content_x: clean(parsed.content_x),
      tags_x: clean(parsed.tags_x),

      // =========================
      // FACEBOOK
      // =========================
      title_facebook: clean(parsed.title_facebook),
      content_facebook: clean(parsed.content_facebook),
      tags_facebook: clean(parsed.tags_facebook),

      // =========================
      // INSTAGRAM
      // =========================
      title_instagram: clean(parsed.title_instagram),
      content_instagram: clean(parsed.content_instagram),
      tags_instagram: clean(parsed.tags_instagram),
    },
  },
];

const article = $('Check WP Category').item.json;
const createResult = $json;

const normalize = (s) =>
  (s || "")
    .toString()
    .trim()
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");

const slugify = (s) =>
  normalize(s)
    .replace(/[^a-z0-9\s-]/g, "")
    .replace(/\s+/g, "-")
    .replace(/-+/g, "-")
    .replace(/^-|-$/g, "");

const finalCategory = article.categoryName || article.category || "Sin categoría";

// Caso 1: se creó bien
if (createResult.id) {
  return [
    {
      json: {
        ...article,
        categoryId: Number(createResult.id),
        categoryName: createResult.name || finalCategory,
        categoryReady: true,
        exists: true,
      },
    },
  ];
}

// Caso 2: falló porque ya existía o no devolvió id
const searchResults = $('Create categories').all();

const targetName = normalize(finalCategory);
const targetSlug = slugify(finalCategory);

const matchedCategory = searchResults.find(item => {
  const j = item.json || {};

  return j.id && (
    normalize(j.name) === targetName ||
    normalize(j.slug) === targetSlug
  );
});

if (matchedCategory) {
  return [
    {
      json: {
        ...article,
        categoryId: Number(matchedCategory.json.id),
        categoryName: matchedCategory.json.name || finalCategory,
        categoryReady: true,
        exists: true,
      },
    },
  ];
}

throw new Error(
  `No se pudo obtener el ID de la categoría. category="${finalCategory}". Resultados GET=${JSON.stringify(searchResults.map(i => i.json))}`
);

const data = $json;

let termId =
  data.error?.additional_data?.[0]?.data?.term_id ||
  data.error?.additional_data?.data?.term_id ||
  data.error?.data?.term_id ||
  data.data?.term_id ||
  null;

if (!termId && data.error?.message) {
  const msg = String(data.error.message);

  const match = msg.match(/"term_id"\s*:\s*(\d+)/) ||
                msg.match(/term_id[^0-9]+(\d+)/);

  if (match) {
    termId = match[1];
  }
}

if (!termId) {
  throw new Error(`No se pudo recuperar term_id del tag existente: ${JSON.stringify(data)}`);
}

return {
  json: {
    tagId: Number(termId),
    tagName: data.tagName || data.name || "",
    tagSlug: data.tagSlug || data.slug || "",
    tagReady: true,
    existed: true
  }
};

