const data = $json;

let rawTags = [];

// PRIORIDAD: tags WordPress
if (
  Array.isArray(data.tags_wordpress) &&
  data.tags_wordpress.length > 0
) {
  rawTags = data.tags_wordpress;

} else if (
  typeof data.tags_wordpress === "string" &&
  data.tags_wordpress.trim()
) {
  rawTags = data.tags_wordpress.split(/[,]+|\s+(?=#)/);

// FALLBACK: tags antiguos
} else if (
  Array.isArray(data.tags) &&
  data.tags.length > 0
) {
  rawTags = data.tags;

} else if (
  typeof data.tags === "string" &&
  data.tags.trim()
) {
  rawTags = data.tags.split(/[,]+|\s+(?=#)/);
}

// FALLBACK automático
if (!rawTags.length) {
  rawTags = [
    data.keyword,
    data.categoryName || data.category
  ];
}

// Limpiar tags
const cleanTags = rawTags
  .map(tag => String(tag || "").trim())
  .map(tag => tag.replace(/^#/, ""))
  .map(tag => tag.trim())
  .filter(Boolean)
  .filter((tag, index, arr) =>
    arr.findIndex(
      t => t.toLowerCase() === tag.toLowerCase()
    ) === index
  );

// Crear items separados para cada tag
return cleanTags.map(tag => ({
  json: {
    ...data,
    tagName: tag
  }
}));

const items = $input.all();

const tagIds = items
  .map(i => Number(i.json.tagId))
  .filter(Boolean);

const tagNames = items
  .map(i => i.json.tagName)
  .filter(Boolean);

return [
  {
    json: {
      tagIds,
      tagNames,
      tagsReady: tagIds.length > 0
    }
  }
];

const data = $json;

// Recuperar datos del formulario original si existe
let mappedData = {};

try {
  const possibleMappedData = $('Map Input Data').item.json;
  if (
    possibleMappedData &&
    typeof possibleMappedData === "object" &&
    !Array.isArray(possibleMappedData)
  ) {
    mappedData = possibleMappedData;
  }
} catch (error) {
  mappedData = {};
}

const requestedSizeRaw =
  data.tamano ||
  mappedData.tamano ||
  data.requestedSizeRaw ||
  "";

const requestedSize = requestedSizeRaw
  .toString()
  .trim()
  .toLowerCase()
  .normalize("NFD")
  .replace(/[\u0300-\u036f]/g, "");

// HTML real del artículo con fallback
const html =
  data.content_wordpress ||
  data.content ||
  "";
// Texto plano para contar palabras reales
const plainText = html
  .replace(/<[^>]+>/g, " ")
  .replace(/&nbsp;/gi, " ")
  .replace(/&amp;/gi, "&")
  .replace(/\s+/g, " ")
  .trim();

const wordCount = plainText
  ? plainText.split(" ").filter(Boolean).length
  : 0;

let normalizedSize = "";
let minWords = 0;
let maxWords = 0;
let targetLabel = "";

if (
  requestedSize.includes("corto") ||
  requestedSize.includes("breve") ||
  requestedSize.includes("400")
) {
  normalizedSize = "corto";
  minWords = 300;
  maxWords = 450;
  targetLabel = "300-450 palabras";

} else if (
  requestedSize.includes("estandar") ||
  requestedSize.includes("estándar") ||
  requestedSize.includes("800") ||
  requestedSize.includes("medio")
) {
  normalizedSize = "estandar";
  minWords = 600;
  maxWords = 900;
  targetLabel = "600-900 palabras";

} else if (
  requestedSize.includes("largo") ||
  requestedSize.includes("extenso") ||
  requestedSize.includes("1500")
) {
  normalizedSize = "largo";
  minWords = 1200;
  maxWords = 1600;
  targetLabel = "1200-1600 palabras";
}

const isValidLength = minWords > 0 && wordCount >= minWords;

return {
  json: {
    ...mappedData,
    ...data,
    requestedSizeRaw,
    normalizedSize,
    wordCount,
    minWords,
    maxWords,
    targetLabel,
    isValidLength,
    retries: Number(data.retries ?? 0),
  },
};

const data = $json;

return {
  json: {
    tagId: Number(data.id),
    tagName: data.name || "",
    tagSlug: data.slug || "",
    tagReady: true,
    existed: false
  }
};
